case 'flush_session': {
  // Force-write the session file to disk if Pi hasn't flushed yet.
  // Pi defers file creation until the first assistant message, but we need
  // the file on disk immediately so the sidebar can display it.
  // After writing, mark flushed=true so Pi's _persist uses appendFileSync
  // instead of openSync('wx') which would fail on an existing file.
  if (sessionManager) {
    const sessionFile = sessionManager.getSessionFile()
    if (sessionFile && !existsSync(sessionFile)) {
      const header = sessionManager.getHeader()
      const entries = sessionManager.getEntries()
      const lines: string[] = []
      if (header) lines.push(JSON.stringify(header))
      for (const entry of entries) {
        lines.push(JSON.stringify(entry))
      }
      const dir = dirname(sessionFile)
      if (!existsSync(dir)) {
        mkdirSync(dir, { recursive: true })
      }
      writeFileSync(sessionFile, lines.join('\n') + '\n', { flag: 'wx' })
      // eslint-disable-next-line @typescript-eslint/no-explicit-any
      ;(sessionManager as any).flushed = true
    }
  }
  send({ channel: 'response', id: cmd.id, command: 'flush_session', success: true })
  break
}

