export function nameSession(sessionPath: string, name: string, cwd?: string, parentSessionPath?: string): boolean {
  try {
    const dir = dirname(sessionPath)
    if (!existsSync(dir)) {
      mkdirSync(dir, { recursive: true })
    }

    if (!existsSync(sessionPath)) {
      const fileName = basename(sessionPath, '.jsonl')
      const idPart = fileName.includes('_') ? fileName.split('_').slice(1).join('_') : randomUUID()
      const header: Record<string, unknown> = {
        type: 'session',
        version: 3,
        id: idPart,
        timestamp: new Date().toISOString(),
        cwd: cwd ?? process.cwd(),
      }
      if (parentSessionPath) {
        header.parentSession = parentSessionPath
      }
      writeFileSync(sessionPath, JSON.stringify(header) + '\n')
    }

    const entry = JSON.stringify({
      type: 'session_info',
      name,
    })
    appendFileSync(sessionPath, entry + '\n')
    return true
  } catch {
    return false
  }
}

