ipcMain.handle('session:newSession', async (_event, name: string, parentSessionPath?: string) => {
  try {
    // 1. Tell Pi to create a new session (with parentSession)
    const command: Record<string, unknown> = { type: 'new_session' }
    if (parentSessionPath) {
      command.parentSession = parentSessionPath
    }
    await piBridge!.sendRpcCommand(command)

    // 2. Set the session name via Pi RPC
    if (name) {
      try {
        await piBridge!.sendRpcCommand({ type: 'set_session_name', name })
      } catch {}
    }

    // 3. Get the new session file path and persist name + parentSession to disk
    //    Pi defers file creation until first assistant message, so we must
    //    create the file ourselves with the correct header (including parentSession)
    //    to avoid race conditions with Pi's lazy flush.
    try {
      const data = (await piBridge!.sendRpcCommand({ type: 'get_state' })) as Record<string, unknown>
      const sessionPath = typeof data.sessionFile === 'string' ? data.sessionFile : null
      if (sessionPath && name) {
        sessionService.nameSession(sessionPath, name, process.cwd(), parentSessionPath)
      }
    } catch {}

    return { success: true }
  } catch (err: unknown) {
    return { success: false, error: err instanceof Error ? err.message : String(err) }
  }
})

